To implement a chat system that supports sending text, files, and images, where files can be downloaded and images displayed directly in the chat, you must handle different types of data separately on both the client and server sides. I will provide an example of how to achieve this using the WebSocket protocol and assuming you are using a server setup that supports binary data (the `ws` library for Node.js would be suitable for this).

**Frontend (Client HTML/Javascript)**

```html
<!-- The HTML setup from before can be used. -->

<script type="text/javascript">
    // ... existing code

    function sendMessage() {
        var messageInput = document.getElementById("message");
        var message = messageInput.value.trim();
        if (message && socket.readyState === WebSocket.OPEN) {
            var data = { type: "text", content: message };
            socket.send(JSON.stringify(data));
            messageInput.value = "";
        } else {
            alert("连接没有开启或消息为空.");
        }
    }

    function sendFile() {
        var fileInput = document.getElementById('fileInput');
        var file = fileInput.files[0];

        if (file && socket.readyState === WebSocket.OPEN) {
            var reader = new FileReader();
            reader.onload = function(event) {
                var data = {
                    type: file.type.startsWith('image/') ? 'image' : 'file',
                    name: file.name,
                    content: event.target.result.split('base64,')[1], // Send as base64 string (without the DataURI prefix)
                    contentType: file.type
                };
                socket.send(JSON.stringify(data));
            };
            reader.readAsDataURL(file);
        } else {
            alert("连接没有开启或未选择文件.");
        }
    }

    socket.onmessage = function(message) {
        var data = JSON.parse(message.data);
        switch (data.type) {
            case 'text':
                // Display text message
                writeToChat(data.content);
                break;
            case 'file':
                // Display file download link
                var link = document.createElement('a');
                link.href = 'data:' + data.contentType + ';base64,' + data.content;
                link.download = data.name;
                link.textContent = "Download " + data.name;
                document.body.appendChild(link);
                writeToChat(link.outerHTML);
                break;
            case 'image':
                // Display image
                var img = new Image();
                img.src = 'data:' + data.contentType + ';base64,' + data.content;
                img.style.maxWidth = '200px'; // Set max width for large images
                img.onload = function() {
                    document.getElementById('responseText').appendChild(img);
                };
                break;
            default:
                console.error("Unknown message type:", data.type);
        }
    };

    // ... existing code
</script>
```

**Backend (Node.js WebSocket Server)**

You can use the `ws` package to create a WebSocket server in Node.js. Here is an example of handling different types of messages:

```javascript
const WebSocket = require('ws');
const server = new WebSocket.Server({ port: 3000 });

server.on('connection', function (ws) {
    ws.on('message', function (message) {
        // Since we're expecting JSON stringified data
        var data = JSON.parse(message);

        switch (data.type) {
            case 'text':
            case 'file':
            case 'image':
                // Broadcast data to all connected clients
                server.clients.forEach(function each(client) {
                    if (client !== ws && client.readyState === WebSocket.OPEN) {
                        client.send(JSON.stringify(data));
                    }
                });
                break;
            default:
                console.error("Unknown message type:", data.type);
        }
    });
});
```

This example assumes that the client sends JSON stringified objects with a `type` field that can be `text`, `file`, or `image`. Based on the `type`, the server broadcasts the data to all connected clients (except the sender). On the client side, the `onmessage` handler determines how to present the data based on its type.

Remember to always validate and possibly sanitize the data sent from the client to avoid security vulnerabilities, such as XSS attacks or binary data manipulation. This code is intended as a starting point and should be properly secured before being used in a production environment.

